 */
public class EgovFileUploadUtil extends EgovFormBasedFileUtil {
	/**
	 * 파일을 Upload 처리한다.
	 *
	 * @param request
	 * @param where
	 * @param maxFileSize
	 * @return
	 * @throws Exception
	 */
	public static List<EgovFormBasedFileVo> uploadFiles(HttpServletRequest request, String where, long maxFileSize) throws Exception {
		List<EgovFormBasedFileVo> list = new ArrayList<>();
		MultipartHttpServletRequest mptRequest = WebUtils.getNativeRequest(request, MultipartHttpServletRequest.class);

		if (mptRequest != null) {//2022.01 Possible null pointer dereference due to return value of called method 조치
			Iterator<?> fileIter = mptRequest.getFileNames();

			while (fileIter.hasNext()) {
				MultipartFile mFile = mptRequest.getFile((String)fileIter.next());

				// 2022.11.11 김혜준 시큐어코딩 처리
				if (mFile == null) {
					continue;
				}

				EgovFormBasedFileVo vo = new EgovFormBasedFileVo();

				String tmp = mFile.getOriginalFilename();

				//2022.01 Possible null pointer dereference due to return value of called method
				if (StringUtils.isNotEmpty(tmp)) {

					if (tmp.lastIndexOf("\\") >= 0) {
						tmp = tmp.substring(tmp.lastIndexOf("\\") + 1);
					}

					vo.setFileName(tmp);
					vo.setContentType(mFile.getContentType());
					vo.setServerSubPath(getTodayString());
					vo.setPhysicalName(getPhysicalFileName());
					vo.setSize(mFile.getSize());

					if (tmp.lastIndexOf(".") >= 0) {
						vo.setPhysicalName(vo.getPhysicalName()); // 2012.11 KISA 보안조치
					}

					if (mFile.getSize() > 0) {
						InputStream is = null;

						try {
							is = mFile.getInputStream();
							saveFile(is, new File(EgovWebUtil.filePathBlackList(
								where + SEPERATOR + vo.getServerSubPath() + SEPERATOR + vo.getPhysicalName())));
						} finally {
							if (is != null) {
								is.close();
							}
						}
						list.add(vo);
					}
				}
			}
		}

		return list;
	}

	/**
	 * 파일을 Upload(확장명 저장 및 확장자 제한) 처리한다.
	 *

 *   2009.08.26  한성곤          최초 생성
 *   2017.03.03  조성원          시큐어코딩(ES)-부적절한 예외 처리[CWE-253, CWE-440, CWE-754]
 *   2019.12.09  신용호          KISA 보안약점 조치 (위험한 형식 파일 업로드) : uploadFiles 삭제  => EgovFileUploadUtil.uploadFilesExt(확장자 기록) 대체
 *   2023.06.27  김혜준          NSR 보안조치 (CKEditor 이미지 보기 기능의 스크립트 실행 취약점)
 *   2025.09.01  이백행          2025년 컨트리뷰션 PMD로 소프트웨어 보안약점 진단하고 제거하기-CloseResource(부적절한 자원 해제)
 *   2025.09.01  이백행          2025년 컨트리뷰션 PMD로 소프트웨어 보안약점 진단하고 제거하기-AssignmentInOperand(피연산자내에 할당문이 사용됨. 해당 코드를 복잡하고 가독성이 떨어지게 만듬)
 *   2025.09.01  이백행          2025년 컨트리뷰션 PMD로 소프트웨어 보안약점 진단하고 제거하기-AvoidReassigningParameters(넘겨받는 메소드 parameter 값을 직접 변경하는 코드 탐지)
 *
 *      </pre>
 */
public class EgovFormBasedFileUtil {
	/** Buffer size */
	public static final int BUFFER_SIZE = 8192;

	public static final String SEPERATOR = File.separator;

	private static final Logger LOGGER = LoggerFactory.getLogger(EgovFormBasedFileUtil.class);

	/**
	 * 오늘 날짜 문자열 취득. ex) 20090101
	 *
	 * @return
	 */
	public static String getTodayString() {
		SimpleDateFormat format = new SimpleDateFormat("yyyyMMdd", Locale.getDefault());

		return format.format(new Date());
	}

	/**
	 * 물리적 파일명 생성.
	 *
	 * @return
	 */
	public static String getPhysicalFileName() {
		return EgovFormBasedUUID.randomUUID().toString().replaceAll("-", "").toUpperCase();
	}

	/**
	 * 파일명 변환.
	 *
	 * @param filename String
	 * @return
	 * @throws Exception
	 */
	protected static String convert(String filename) throws Exception {
		// return java.net.URLEncoder.encode(filename, "utf-8");
		return filename;
	}

	/**
	 * Stream으로부터 파일을 저장함.
	 *
	 * @param is   InputStream
	 * @param file File
	 * @throws IOException
	 */
	public static long saveFile(InputStream is, File file) throws IOException {
		// KISA 보안약점 조치 (2018-10-29, 윤창원)
		if (file.getParentFile() == null) {
			LOGGER.debug("file.getParentFile() is null");
			throw new RuntimeException("file.getParentFile() is null");
		}

		// 디렉토리 생성
		if (!file.getParentFile().exists()) {
			// 2017.03.03 조성원 시큐어코딩(ES)-부적절한 예외 처리[CWE-253, CWE-440, CWE-754]
			if (file.getParentFile().mkdirs()) {
				LOGGER.debug("[file.mkdirs] file : Directory Creation Success");
			} else {
				LOGGER.error("[file.mkdirs] file : Directory Creation Fail");
			}
		}

		return FileCopyUtils.copy(is, new FileOutputStream(file));
	}

	/**
	 * 파일을 Upload 처리한다. (삭제) EgovFileUploadUtil.uploadFilesExt(확장자 확인) 대체
